import React, { useState } from "react";
import './Logout.css';
import './Welcome';
import { useLocation, useNavigate } from "react-router";
import axios from "axios";
function Logout () {
    const [data, setData] = useState(''); 
    const location = useLocation();
    const navigate = useNavigate();
    const getCall = (userName) => {
        axios.get(`http://localhost:8080/user/${userName}/items`).then(response => setData(response.data.id))
    }
    return <div className="nav-bar">
    <div className="header">
    <a href="#default" className="logo">Productiv</a>
    <div className="header-right">
    <a href="#home">My Account</a>
    <a href="#contact" onClick={() => navigate('/')} >Logout</a>
  </div>
    </div>
        <h1> Welcome {getCall}! </h1>
        <div>
        <table>
        <tr>
            <th>{data}</th>
            <th>{data}</th>
            <th>{data}</th>
        </tr>
        <tr>
            <td>{data}</td>
            <td>{data}</td>
            <td>{data}</td>
        </tr>
        <tr>
            <td>{data}</td>
            <td>{data}</td>
            <td>{data}</td>
        </tr>
        </table>
        </div>
    </div>
}

export default Logout;
